MERGE bus_vehicles AS t USING (SELECT N'QT-BUS-001' AS vehicle_code) AS src ON t.vehicle_code=src.vehicle_code WHEN MATCHED THEN UPDATE SET plate=N'QT-BUS-001', license_plate=NULL, province_code=N'QT', route_code=N'QT-01', vehicle_name=N'Xe buýt QT-BUS-001', vehicle_type=N'Xe buýt', status='active', capacity=40, avg_speed_kmh=30, min_speed_kmh=20, max_speed_kmh=40, updated_at=SYSDATETIME() WHEN NOT MATCHED THEN INSERT(vehicle_code,plate,license_plate,province_code,route_code,vehicle_name,vehicle_type,status,capacity,avg_speed_kmh,min_speed_kmh,max_speed_kmh) VALUES(N'QT-BUS-001',N'QT-BUS-001',NULL,N'QT',N'QT-01',N'Xe buýt QT-BUS-001',N'Xe buýt','active',40,30,20,40);
